/**
 * Request notification permission, get FCM token, and save it to the user's
 * record in Firestore (settings/users → list[].fcmTokens).
 * Tokens are stored as an array so every device the user logs in on gets
 * notifications. Capped at 10 tokens to avoid unbounded growth.
 * Called once after the user selects their identity at login.
 */
async function registerFCMToken(userId, force=false) {
  if (!messaging || !VAPID_KEY || VAPID_KEY === "PASTE_YOUR_VAPID_KEY_HERE") return "no_messaging";
  try {
    // On iOS, Notification API may not exist unless added to Home Screen as PWA
    if (!("Notification" in window)) return "no_notification_api";

    const permission = await Notification.requestPermission();
    if (permission !== "granted") return "permission_denied";

    // Explicitly register the Firebase messaging SW and wait for it to activate.
    // Passing serviceWorkerRegistration to getToken is required for reliable
    // token generation on mobile (especially Android Chrome & iOS Safari PWA).
    let swReg = null;
    if ("serviceWorker" in navigator) {
      try {
        swReg = await navigator.serviceWorker.register("/firebase-messaging-sw.js");
        // Force update so stale SWs don't serve old token logic — critical for
        // keeping the SW current after deployments.
        await swReg.update().catch(() => {});
        await navigator.serviceWorker.ready;
      } catch(e) {
        console.warn("[HE] SW register failed:", e.message);
      }
    }

    const tokenOptions = { vapidKey: VAPID_KEY };
    if (swReg) tokenOptions.serviceWorkerRegistration = swReg;

    // When forcing a refresh (daily rotation, or user hit "Enable Notifications"
    // after a failed test), delete the cached token first. Otherwise the SDK
    // returns the same stale token that was already pruned server-side — this
    // was the "token registered but server says no tokens" infinite loop.
    if (force) {
      try { await deleteToken(messaging); } catch(e) { /* fine if already gone */ }
    }

    const token = await getToken(messaging, tokenOptions);
    if (!token) return "no_token";

    console.log("[HE] FCM token generated (first 20):", token.slice(0,20), "userId:", userId);

    const snap = await getDoc(doc(db, "settings", "users"));
    if (!snap.exists()) return "no_user_doc";
    const rawList = snap.data().list || [];
    const targetUser = rawList.find(u => u.id === userId);
    if (!targetUser) {
      console.warn("[HE] FCM registration: userId not found in users list", {
        userId, availableIds: rawList.map(u => u.id)
      });
      return "user_not_in_list";
    }
    const list = rawList.map(u => {
      if (u.id !== userId) return u;
      const existing = Array.isArray(u.fcmTokens) ? u.fcmTokens
        : u.fcmToken ? [u.fcmToken] : [];
      // Always additive — never wipe the array, even on force refresh.
      // Other devices' tokens must be preserved. Dead tokens get pruned
      // server-side on the next send attempt; worst case the array grows
      // by one stale token which the .slice(-10) cap handles.
      const merged = existing.includes(token) ? existing : [...existing, token];
      return { ...u, fcmTokens: merged.slice(-10) };
    });
    await setDoc(doc(db, "settings", "users"), { list });
    console.log("[HE] FCM token registered" + (force ? " (forced refresh)" : ""),
      "→ user now has", list.find(u=>u.id===userId)?.fcmTokens?.length || 0, "token(s)");
    return "ok";
  } catch (e) {
    console.warn("[HE] FCM registration failed:", e.message);
    return "error:" + e.message;
  }
}

// Handle foreground messages (app is open) — show a brief alert-style banner.
// Reads from payload.data since we send data-only messages to prevent double notifications.
// Also forwards jobId + section so the toast can deep-link on tap.
if (messaging) {
  onMessage(messaging, payload => {
    const title   = payload.data?.title   || payload.notification?.title;
    const body    = payload.data?.body    || payload.notification?.body;
    const jobId   = payload.data?.jobId   || "";
    const section = payload.data?.section || "";
    if (title || body) {
      const ev = new CustomEvent("he-push", { detail: { title, body, jobId, section } });
      window.dispatchEvent(ev);
    }
  });
}
