// ── Stage Sections ────────────────────────────────────────────

// Effective status — falls back to deriving from % if no status stored
const effRS = j => {
  if(j.tempPed) {
    const s = j.tempPedStatus||"";
    if(s==="completed") return "complete";
    if(s==="scheduled") return "scheduled";
    if(s==="ready") return "waiting_date";
    return "";
  }
  if(j.roughStatus) return j.roughStatus;
  const p=parseInt(j.roughStage)||0; return p===100?"complete":p>0?"inprogress":"";
}; // date_confirmed triggers scheduling task
const effFS = j => {
  if(j.tempPed) return ""; // temp peds don't have a finish stage
  if(j.finishStatus) return j.finishStatus;
  const p=parseInt(j.finishStage)||0; return p===100?"complete":p>0?"inprogress":"";
};

// ── Simplified scheduling state (3 values: needsSched | scheduled | ongoing) ──
// Derives a single indicator from whatever the user's current status + mode is,
// so the card can show ONE pill that answers "do I need to put crew on this?"
// Source of truth is still roughStatus/finishStatus for lifecycle; this is a view
// on top. Writing via applyScheduleMode keeps both in sync.
const deriveScheduleMode = (job, phase) => {
  const st   = phase==="rough" ? job.roughStatus : job.finishStatus;
  const mode = phase==="rough" ? job.roughInProgressMode : job.finishInProgressMode;
  if(!st) return null;
  if(st==="complete" || st==="invoice") return null;
  if(st==="inprogress") {
    if(mode==="scheduled" || mode==="needsSched" || mode==="ongoing") return mode;
    return "ongoing"; // default for in-progress when no explicit sub-state
  }
  if(st==="scheduled") return "scheduled";
  // "date_confirmed" → GC has given us a start date; we just need a crew.
  // "waiting_date"   → we're still waiting on a start date from the GC — nothing
  //                     to schedule yet, so no pill (was showing "Needs Sched"
  //                     which implied action on our side that we can't take).
  if(st==="date_confirmed") return "needsSched";
  return null;
};
const applyScheduleMode = (job, phase, next) => {
  // When user clicks the pill, update both the lifecycle status and the sub-mode
  // so things stay coherent. Never touches complete/invoice.
  const stKey   = phase==="rough" ? "roughStatus"          : "finishStatus";
  const modeKey = phase==="rough" ? "roughInProgressMode"  : "finishInProgressMode";
  const curSt = job[stKey];
  // Leaving complete/invoice alone: if somehow pill is active there, don't clobber
  if(curSt==="complete" || curSt==="invoice") return {};
  if(next==="ongoing") {
    // Flip to in-progress/ongoing
    return { [stKey]: "inprogress", [modeKey]: "ongoing" };
  }
  if(next==="needsSched") {
    // If already in-progress, keep in-progress with needsSched sub-state
    if(curSt==="inprogress") return { [modeKey]: "needsSched" };
    // Otherwise, map to date_confirmed (needs to be scheduled)
    return { [stKey]: "date_confirmed", [modeKey]: "needsSched" };
  }
  if(next==="scheduled") {
    // If already in-progress, keep in-progress with scheduled sub-state
    if(curSt==="inprogress") return { [modeKey]: "scheduled" };
    return { [stKey]: "scheduled", [modeKey]: "scheduled" };
  }
  return {};
};

// ── Status update inline editor ──────────────────────────────────────────────
// Wraps the amber-left-stripe status update display so it can be edited in
// place anywhere it shows up (Board cards, Forecast rows, Crew Planner rows,
// JobDetail). Click the text to edit; Enter saves, Escape cancels, blur saves.
// `onSave(patch)` should apply the patch to the job (same shape as elsewhere:
// statusUpdate/statusUpdateBy/statusUpdateAt).
function StatusUpdateInline({ job, onSave, identity=null, fontSize=11, maxWidth=280, stripeColor="#f59e0b", style={}, showEmpty=false, placeholder="Add status note…" }) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(job.statusUpdate || "");
  const inputRef = useRef(null);

  useEffect(() => {
    if(editing && inputRef.current) { inputRef.current.focus(); inputRef.current.select(); }
  }, [editing]);

  useEffect(() => {
    // Keep local draft in sync with external state when not editing
    if(!editing) setDraft(job.statusUpdate || "");
  }, [job.statusUpdate, editing]);

  const commit = () => {
    const v = (draft||"").trim();
    const current = (job.statusUpdate||"").trim();
    if(v === current) { setEditing(false); return; }
    const patch = {
      statusUpdate: v,
      statusUpdateBy: v ? (identity?.name || job.statusUpdateBy || "") : "",
      statusUpdateAt: v ? new Date().toISOString() : "",
    };
    try { onSave && onSave(patch); } catch(_){}
    setEditing(false);
  };

  const cancel = () => { setDraft(job.statusUpdate||""); setEditing(false); };

  if(editing) {
    return (
      <input
        ref={inputRef}
        value={draft}
        onChange={e=>setDraft(e.target.value)}
        onBlur={commit}
        onKeyDown={e=>{
          if(e.key==="Enter") { e.preventDefault(); commit(); }
          else if(e.key==="Escape") { e.preventDefault(); cancel(); }
        }}
        onClick={e=>e.stopPropagation()}
        onMouseDown={e=>e.stopPropagation()}
        placeholder={placeholder}
        style={{
          fontSize, fontWeight: 500, color: "var(--text)",
          borderLeft: `3px solid ${stripeColor}`,
          padding: "3px 8px 3px 8px",
          background: "#fffbeb",
          borderTop: `1px solid ${stripeColor}55`,
          borderRight: `1px solid ${stripeColor}55`,
          borderBottom: `1px solid ${stripeColor}55`,
          borderRadius: 4,
          outline: "none", minWidth: 160, maxWidth: typeof maxWidth==="number"? maxWidth+40 : maxWidth,
          lineHeight: 1.4, fontFamily: "inherit",
          ...style,
        }}
      />
    );
  }

  if(!job.statusUpdate) {
    if(!showEmpty || !onSave) return null;
    return (
      <button type="button"
        onClick={e=>{ e.stopPropagation(); setEditing(true); }}
        style={{
          fontSize, color: "var(--dim)", fontWeight: 500,
          background: "none", border: `1px dashed var(--border)`,
          borderRadius: 4, padding: "2px 8px",
          cursor: "pointer", fontFamily: "inherit",
          ...style,
        }}>+ status</button>
    );
  }

  return (
    <div
      onClick={e=>{ if(onSave){ e.stopPropagation(); setEditing(true); } }}
      title={`Status set by ${job.statusUpdateBy||"someone"}${job.statusUpdateAt?` · ${timeAgo(job.statusUpdateAt)}`:""}${onSave?" · click to edit":""}`}
      style={{
        fontSize, color: "var(--text)", fontWeight: 500,
        borderLeft: `3px solid ${stripeColor}`,
        paddingLeft: 8, paddingRight: 4,
        display: "inline-flex", alignItems: "center", maxWidth: "100%",
        lineHeight: 1.4, cursor: onSave ? "pointer" : "default",
        ...style,
      }}
    >
      <span style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth}}>{job.statusUpdate}</span>
    </div>
  );
}

const STAGE_SECTIONS = [

  // Quick Jobs
  { key:"quickNew",        label:"Quick Jobs — New",              color:"#6b7280",
    test: j => !!j.quickJob && (j.quickJobStatus||"new")==="new" },

  { key:"quickScheduled",  label:"Quick Jobs — Scheduled",        color:"#2563eb",
    test: j => !!j.quickJob && j.quickJobStatus==="scheduled" },

  { key:"quickInProgress", label:"Quick Jobs — In Progress",      color:"#0ea5e9",
    test: j => !!j.quickJob && j.quickJobStatus==="inprogress" },

  // Temp Peds
  { key:"tempPedReady",    label:"Temp Peds — Ready to Schedule", color:"#8b5cf6",
    test: j => !!j.tempPed && (!j.tempPedStatus||j.tempPedStatus==="ready") },

  { key:"tempPedScheduled", label:"Temp Peds — Scheduled",           color:"#2563eb",
    test: j => !!j.tempPed && j.tempPedStatus==="scheduled" },

  // Full Jobs
  { key:"prep",         label:"Pre Job Prep",              color:"#0d9488",
    test: j => !j.tempPed && !j.quickJob && !allPrepDone(j) },

  { key:"roughNotStarted", label:"Rough — Not Started",   color:"#64748b",
    test: j => { const rs=effRS(j); return !j.tempPed && !j.quickJob && allPrepDone(j) && (!rs||rs==="waiting_date"||rs==="date_confirmed"||rs==="scheduled"); } },

  { key:"roughHold",    label:"Rough — On Hold",           color:"#ca8a04",
    test: j => !j.tempPed && !j.quickJob && effRS(j) === "waiting" },

  { key:"rough",        label:"Rough In Progress",         color:"#2563eb",
    test: j => !j.tempPed && !j.quickJob && effRS(j) === "inprogress" },

  { key:"between",      label:"In Between",                color:"#e8a020",
    test: j => { if(j.tempPed||j.quickJob) return false; const rs=effRS(j); const fs=effFS(j); return rs==="complete"&&(!fs||fs==="waiting_date"||fs==="date_confirmed"||fs==="scheduled"); } },

  { key:"finishHold",   label:"Finish — On Hold",          color:"#ca8a04",
    test: j => !j.tempPed && !j.quickJob && effFS(j) === "waiting" },

  { key:"finish",       label:"Finish In Progress",        color:"#0ea5e9",
    test: j => !j.tempPed && !j.quickJob && effFS(j) === "inprogress" },

  // All completed — quick jobs, temp peds, and full jobs in one section
  { key:"complete",     label:"Completed",                 color:"#22c55e",
    test: j => (j.quickJob && (j.quickJobStatus==="complete"||j.quickJobStatus==="invoice")) ||
               (j.tempPed && j.tempPedStatus==="completed") ||
               (!j.tempPed && !j.quickJob && effFS(j) === "complete") },

];


function StageSectionList({ jobs, JobRow, TempPedCard, onSelectJob, onSaveJob, onDeleteJob, fc, startCollapsed=true }) {

  const initCollapsed = () => Object.fromEntries(STAGE_SECTIONS.map(s=>[s.key,startCollapsed]));
  const [collapsed, setCollapsed] = useState(initCollapsed);

  const toggle = key => setCollapsed(c=>({...c,[key]:!c[key]}));


  return (

    <div>

      {STAGE_SECTIONS.map(sec => {

        const sJobs = (() => {
          const filtered = jobs.filter(sec.test);
          // Get the most relevant date for a job in this section
          const getDate = j => {
            const rs = effRS(j), fs = effFS(j);
            // Prefer projected start dates, fall back to status dates
            if(fs==="scheduled"||fs==="date_confirmed"||fs==="inprogress") return j.finishProjectedStart||j.finishStatusDate||j.roughProjectedStart||j.roughStatusDate||"";
            if(rs==="scheduled"||rs==="date_confirmed"||rs==="inprogress") return j.roughProjectedStart||j.roughStatusDate||"";
            return j.roughProjectedStart||j.roughStatusDate||j.finishProjectedStart||j.finishStatusDate||"";
          };
          return filtered.sort((a,b)=>{
            const da=getDate(a), db=getDate(b);
            if(!da&&!db) return 0;
            if(!da) return 1;
            if(!db) return -1;
            return new Date(da)-new Date(db);
          });
        })();

        if(sJobs.length===0) return null;

        const isCollapsed = collapsed[sec.key];

        return (

          <div key={sec.key} style={{marginBottom:24}}>

            <div

              onClick={()=>toggle(sec.key)}

              style={{display:"flex",alignItems:"center",gap:10,marginBottom:10,

                paddingBottom:8,borderBottom:`2px solid ${sec.color}33`,cursor:"pointer",

                userSelect:"none"}}>

              <div style={{width:8,height:8,borderRadius:"50%",background:sec.color,flexShrink:0}}/>

              <div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:18,

                letterSpacing:"0.08em",color:sec.color}}>{sec.label}</div>

              <div style={{background:`${sec.color}18`,border:`1px solid ${sec.color}33`,

                borderRadius:99,padding:"2px 10px",fontSize:11,color:sec.color,fontWeight:700}}>

                {sJobs.length}

              </div>

              <div style={{marginLeft:"auto",color:sec.color,fontSize:13,fontWeight:700}}>

                {isCollapsed ? "▸" : "▾"}

              </div>

            </div>

            {!isCollapsed && sJobs.map(job=>(
              job.quickJob
                ? <QuickJobCard key={job.id} job={job} onOpen={onSelectJob} onUpdate={onSaveJob} onDelete={onDeleteJob}/>
                : job.tempPed
                ? <TempPedCard key={job.id} job={job} onOpen={onSelectJob} onUpdate={onSaveJob} onDelete={onDeleteJob}/>
                : <JobRow key={job.id} job={job} fc={fc||undefined} showForeman={!fc}/>
            ))}

          </div>

        );

      })}

    </div>

  );

}


